    90→      confidence: attr.confidence,
    91→      detectionMethod: attr.detectionMethod,
    92→      evidence: attr.detectionEvidence,
    93→      detectedAt: new Date(),
    94→    };
    95→  }
    96→
    97→  // Track performance in session
    98→  const duration = Date.now() - startTime;
    99→  if (!session.performanceMetrics) {
   100→    session.performanceMetrics = {
   101→      totalDurationMs: 0,
   102→      avgEmailDurationMs: 0,
   103→      parallelStagesCount: 0,
   104→      databaseBatchOps: 0,
   105→    };
   106→  }
   107→  session.performanceMetrics.parallelStagesCount += 1;
   108→
   109→  // Update result processing duration
   110→  result.processingDurationMs += duration;
   111→
   112→  // Add parallel stage result tracking
   113→  result.parallelStageResults.push({
   114→    stageId: `attribute_detection_${result.id}`,
   115→    stageName: 'attributeDetection',
   116→    executionTimeMs: duration,
   117→    parallelWithStages: [], // This stage can run in parallel
   118→    dependentOnStages: ['ruleScoring'], // Depends on earlier stages
   119→    cacheHitsCount: 0,
   120→    errorCount: 0,
   121→  });
   122→
   123→  // Update explainability trace (convert to ExplainabilityTrace.AttributeDetectionResult format)
   124→  result.explainabilityTrace.attributeDetection = detectedAttributes.map((attr) => ({
   125→    attribute: attr.attributeName,
   126→    detected: true,
   127→    detectionMethod:
   128→      attr.detectionMethod === 'pattern' || attr.detectionMethod === 'domainLookup' ? 'direct' : 'derived',
