   140→  result.explainabilityTrace.stageTimings['attributeDetection'] = duration;
   141→  result.explainabilityTrace.configurationRefs['attributeDetection'] = 'attributes.detectors';
   142→}
   143→
   144→/**
   145→ * Detect pattern-based attributes using configured detectors
   146→ */
   147→function detectPatternAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   148→  const detectors = config.attributes?.detectors || [];
   149→  const detectedAttributes: DetectedAttribute[] = [];
   150→
   151→  for (const detector of detectors) {
   152→    try {
   153→      const detection = applyDetector(email, detector);
   154→      if (detection.detected) {
   155→        detectedAttributes.push({
   156→          attributeName: detector.attribute,
   157→          attributeValue: detection.value as string | number | boolean,
   158→          detectionMethod: 'pattern',
   159→          detectionEvidence: detection.evidence || 'Pattern match',
   160→          confidence: 0.8, // Default confidence for pattern matches
   161→        });
   162→      }
   163→    } catch (error) {
   164→      // Log error but continue processing
   165→      console.warn(`Error applying detector for ${detector.attribute}:`, error);
   166→    }
   167→  }
   168→
   169→  return detectedAttributes;
   170→}
   171→
   172→/**
   173→ * Apply individual detector pattern to email content
   174→ */
   175→function applyDetector(
   176→  email: EmailMessage,
   177→  detector: AttributeDetector
   178→): { detected: boolean; value?: unknown; evidence?: string } {
   179→  const { field, operation, values } = detector;
   180→
   181→  // Get the field content to search
   182→  let searchContent = '';
   183→  switch (field) {
   184→    case 'body':
   185→      searchContent = extractEmailBodyText(email);
   186→      break;
   187→    case 'subject':
   188→      searchContent = email.subject || '';
   189→      break;
   190→    case 'from.address':
   191→      searchContent = email.from?.email || '';
   192→      break;
   193→    case 'from.name':
   194→      searchContent = email.from?.name || '';
   195→      break;
   196→    default:
   197→      console.warn(`Unknown field type for detector: ${field}`);
   198→      return { detected: false };
   199→  }
   200→
   201→  // Apply detection operation
   202→  switch (operation) {
   203→    case 'containsAny':
   204→      for (const value of values) {
   205→        if (searchContent.toLowerCase().includes(value.toLowerCase())) {
   206→          return {
   207→            detected: true,
   208→            value: true,
   209→            evidence: `Found "${value}" in ${field}`,
   210→          };
   211→        }
   212→      }
   213→      break;
   214→
   215→    case 'regexAny':
   216→      for (const pattern of values) {
   217→        try {
   218→          const regex = new RegExp(pattern, 'ig'); // Add global flag for better matching
   219→          const match = searchContent.match(regex);
   220→          if (match) {
   221→            // For amount patterns, try to match the longest currency pattern
   222→            let bestMatch = match[0];
   223→            if (pattern.includes('\\$\\d+')) {
   224→              // Special handling for currency amounts - match full amounts with decimals
   225→              const fullAmountRegex = /\$\d+(?:\.\d{2})?/g;
   226→              const fullMatches = searchContent.match(fullAmountRegex);
   227→              if (fullMatches && fullMatches.length > 0) {
   228→                bestMatch = fullMatches[0]; // Use the first full amount match
   229→              }
   230→            }
   231→            return {
   232→              detected: true,
   233→              value: true,
   234→              evidence: `Regex "${pattern}" matched: "${bestMatch}" in ${field}`,
   235→            };
   236→          }
   237→        } catch (error) {
   238→          console.warn(`Invalid regex pattern: ${pattern}`, error);
   239→          continue;
   240→        }
   241→      }
   242→      break;
   243→
   244→    case 'startsWith':
   245→      for (const value of values) {
   246→        if (searchContent.toLowerCase().startsWith(value.toLowerCase())) {
   247→          return {
   248→            detected: true,
   249→            value: true,
   250→            evidence: `${field} starts with "${value}"`,
   251→          };
   252→        }
   253→      }
   254→      break;
   255→
   256→    case 'endsWith':
   257→      for (const value of values) {
   258→        if (searchContent.toLowerCase().endsWith(value.toLowerCase())) {
   259→          return {
   260→            detected: true,
   261→            value: true,
   262→            evidence: `${field} ends with "${value}"`,
   263→          };
   264→        }
   265→      }
   266→      break;
   267→
   268→    default:
   269→      console.warn(`Unknown operation type: ${operation}`);
   270→  }
   271→
   272→  return { detected: false };
   273→}
   274→
   275→/**
   276→ * Detect derived attributes using logical rules
   277→ */
   278→function detectDerivedAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   279→  const settings = config.settings?.attributeProcessing;
   280→  const detectedAttributes: DetectedAttribute[] = [];
   281→
   282→  // Derive selfSent attribute (if enabled, default true)
   283→  const detectSelfSent = !settings || settings.detectSelfSent !== false;
   284→  if (detectSelfSent) {
   285→    const selfSent = deriveSelfSent(email);
   286→    if (selfSent) {
   287→      detectedAttributes.push(selfSent);
   288→    }
   289→  }
   290→
   291→  // Domain-based derivations (if enabled, default true)
   292→  const resolveDomains = !settings || settings.resolveDomains !== false;
   293→  if (resolveDomains) {
   294→    // Derive fromFinancialInstitution attribute
   295→    const financialInstitution = deriveFromFinancialInstitution(email, config);
   296→    if (financialInstitution) {
   297→      detectedAttributes.push(financialInstitution);
   298→    }
   299→
   300→    // Derive fromNewsletterSource attribute
   301→    const newsletterSource = deriveFromNewsletterSource(email, config);
   302→    if (newsletterSource) {
   303→      detectedAttributes.push(newsletterSource);
   304→    }
   305→
   306→    // Derive fromLogisticsCarrier attribute
   307→    const logisticsCarrier = deriveFromLogisticsCarrier(email, config);
   308→    if (logisticsCarrier) {
   309→      detectedAttributes.push(logisticsCarrier);
   310→    }
   311→  }
   312→
   313→  // Gmail category derivations (always enabled - based on Gmail API labelIds)
   314→  const gmailCategories = deriveGmailCategories(email);
   315→  detectedAttributes.push(...gmailCategories);
   316→
   317→  return detectedAttributes;
   318→}
   319→
   320→/**
   321→ * Derive selfSent attribute - email sent from user to self
   322→ */
   323→function deriveSelfSent(email: EmailMessage): DetectedAttribute | null {
   324→  const userAddresses = getUserAddresses();
   325→  const fromAddress = email.from?.email?.toLowerCase();
   326→
   327→  // Check if from address is user address
   328→  if (!fromAddress || !userAddresses.includes(fromAddress)) {
   329→    return null;
   330→  }
   331→
   332→  // Check if all recipients are user addresses
   333→  const allRecipients: string[] = [];
   334→  if (email.to) {
   335→    allRecipients.push(...email.to.map((addr) => addr.email.toLowerCase()));
   336→  }
   337→  if (email.cc) {
   338→    allRecipients.push(...email.cc.map((addr) => addr.email.toLowerCase()));
   339→  }
   340→  if (email.bcc) {
   341→    allRecipients.push(...email.bcc.map((addr) => addr.email.toLowerCase()));
   342→  }
   343→
   344→  const allRecipientsAreUser = allRecipients.length > 0 && allRecipients.every((addr) => userAddresses.includes(addr));
   345→
   346→  // Check for List-Id header (exclude mailing lists)
   347→  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
   348→
   349→  if (allRecipientsAreUser && !hasListId) {
   350→    return {
   351→      attributeName: 'selfSent',
   352→      attributeValue: true,
   353→      detectionMethod: 'derived',
   354→      detectionEvidence: 'All recipients match user addresses',
   355→      confidence: 0.9,
   356→    };
   357→  }
   358→
   359→  return null;
   360→}
   361→
   362→/**
   363→ * Derive fromFinancialInstitution attribute using domain lookup
   364→ */
   365→function deriveFromFinancialInstitution(
   366→  email: EmailMessage,
   367→  config: AttributeDetectionStageConfig
   368→): DetectedAttribute | null {
   369→  const fromAddress = email.from?.email?.toLowerCase();
   370→  if (!fromAddress) return null;
   371→
   372→  const fromDomain = extractBaseDomain(fromAddress);
   373→  const financialDomains = getFinancialDomains(config);
   374→
   375→  if (financialDomains.includes(fromDomain)) {
   376→    return {
   377→      attributeName: 'fromFinancialInstitution',
   378→      attributeValue: true,
   379→      detectionMethod: 'domainLookup',
   380→      detectionEvidence: fromDomain,
   381→      confidence: 0.85,
   382→    };
   383→  }
   384→
   385→  return null;
   386→}
   387→
   388→/**
   389→ * Derive fromNewsletterSource attribute
   390→ */
   391→function deriveFromNewsletterSource(
   392→  email: EmailMessage,
   393→  config: AttributeDetectionStageConfig
   394→): DetectedAttribute | null {
   395→  const fromAddress = email.from?.email?.toLowerCase();
   396→  if (!fromAddress) return null;
   397→
   398→  const fromDomain = extractBaseDomain(fromAddress);
   399→  const newsletterDomains = getNewsletterDomains(config);
   400→
   401→  // Check domain match
   402→  if (newsletterDomains.includes(fromDomain)) {
   403→    return {
   404→      attributeName: 'fromNewsletterSource',
   405→      attributeValue: true,
   406→      detectionMethod: 'domainLookup',
   407→      detectionEvidence: fromDomain,
   408→      confidence: 0.8,
   409→    };
   410→  }
   411→
   412→  // Check List-Id header presence
   413→  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
   414→  if (hasListId) {
   415→    return {
   416→      attributeName: 'fromNewsletterSource',
   417→      attributeValue: true,
   418→      detectionMethod: 'derived',
   419→      detectionEvidence: 'List-Id header present',
   420→      confidence: 0.85,
   421→    };
   422→  }
   423→
   424→  return null;
   425→}
   426→
   427→/**
   428→ * Derive fromLogisticsCarrier attribute
